#include <stdio.h>

int main() {
    int a, b;
    char op;
    scanf("%d %d %c", &a, &b, &op);

    switch (op) {
        case '+':
            printf("%d\n", a + b);
            break;
        case '-':
            printf("%d\n", a - b);
            break;
        case '*':
            printf("%d\n", a * b);
            break;
        case '/':
            printf("%.2f\n", (double)a / b);
            break;
        case '%':
            printf("%d\n", a % b);
            break;
        default:
            printf("Invalid operator\n");
    }

    return 0;
}

